// v0.9：清洗 + 去重 + AI 評分
const GEMINI_API_KEY = $env.GEMINI_API_KEY;
const items = $input.all();
const rows = items[0]?.json ? items.map(i => i.json) : [];

// Step 1: 欄位正規化
const normalize = (r) => {
  const out = {};
  out.name = String(r.name || r.Name || r.姓名 || '').trim();
  out.email = String(r.email || r.Email || '').trim().toLowerCase();
  let phone = String(r.phone || r.Phone || r.電話 || '').replace(/[^0-9+]/g, '');
  if (phone.startsWith('09') && phone.length === 10) phone = '+886' + phone.slice(1);
  if (phone.startsWith('886')) phone = '+' + phone;
  out.phone = phone;
  out.company = String(r.company || r.Company || r.公司 || '').trim();
  out.source = r.source || r.Source || 'unknown';
  return out;
};

const cleaned = rows.map(normalize).filter(r => r.email);

// Step 2: 去重（以 email 為 key）
const uniq = {};
for (const r of cleaned) if (!uniq[r.email]) uniq[r.email] = r;
const dedup = Object.values(uniq);

// Step 3: AI 評分（一次性 prompt，避免 N 次 API call）
const sample = dedup.slice(0, 50);
const prompt = '你是 B2B 銷售評分助手。對下列每筆 lead 評 hot/warm/cold 三級：\n\n標準：\n- hot：公司名清楚 + email 是企業 domain（非 gmail/yahoo）+ 含完整 phone\n- warm：以上滿足 2 條\n- cold：以上少於 2 條，或公司名空白\n\n回 JSON array（順序對齊）：[{"score":"hot"}, {"score":"warm"}, ...]\n\n<leads>\n' + JSON.stringify(sample.map((r, i) => ({i, name: r.name, email: r.email, phone: r.phone, company: r.company}))) + '\n</leads>';

let scores = sample.map(() => 'cold');
try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent',
    headers: { 'Content-Type': 'application/json', 'x-goog-api-key': GEMINI_API_KEY },
    body: {
      contents: [{ role: 'user', parts: [{ text: prompt }] }],
      generationConfig: { temperature: 0.2, maxOutputTokens: 2000, thinkingConfig: { thinkingBudget: 0 } }
    },
    json: true,
    timeout: 60000
  });
  const raw = response.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const m = raw.replace(/^```\w*\n?/, '').replace(/\n?```$/, '').match(/\[[\s\S]*\]/);
  if (m) {
    const arr = JSON.parse(m[0]);
    scores = arr.map(x => ['hot','warm','cold'].includes(x.score) ? x.score : 'cold');
  }
} catch (err) {}

for (let i = 0; i < sample.length; i++) sample[i].score = scores[i] || 'cold';
for (let i = sample.length; i < dedup.length; i++) dedup[i].score = 'cold';

const hot = dedup.filter(r => r.score === 'hot').length;
const warm = dedup.filter(r => r.score === 'warm').length;
const cold = dedup.filter(r => r.score === 'cold').length;

return [{
  json: {
    rowsOriginal: rows.length,
    rowsAfterClean: cleaned.length,
    rowsAfterDedup: dedup.length,
    duplicatesRemoved: cleaned.length - dedup.length,
    hot, warm, cold,
    cleanedRows: dedup
  }
}];

// 組 cleaned CSV + Markdown report + Telegram
const d = $input.first().json;
const rows = d.cleanedRows || [];

// CSV
const headers = ['name','email','phone','company','source','score'];
const csvLines = [headers.join(',')];
for (const r of rows) {
  const escape = (v) => '"' + String(v || '').replace(/"/g, '""') + '"';
  csvLines.push(headers.map(h => escape(r[h])).join(','));
}
const csv = csvLines.join('\n');

// Markdown report
const today = new Date().toISOString().slice(0, 10);
const topHot = rows.filter(r => r.score === 'hot').slice(0, 10);
const md = '# 線索清洗報告 · ' + today + '\n\n' +
  '## 統計\n' +
  '- 原始：' + d.rowsOriginal + ' 筆\n' +
  '- 清洗後：' + d.rowsAfterClean + ' 筆（缺 email 自動移除）\n' +
  '- 去重後：' + d.rowsAfterDedup + ' 筆（移除 ' + d.duplicatesRemoved + ' 筆重複）\n\n' +
  '## AI 評分\n' +
  '- 🔥 hot：' + d.hot + ' 筆\n' +
  '- ☀️ warm：' + d.warm + ' 筆\n' +
  '- ❄️ cold：' + d.cold + ' 筆\n\n' +
  '## 高優先 hot 線索（前 10）\n' +
  topHot.map(r => '- **' + r.name + '** · ' + r.company + ' · ' + r.email + ' · ' + r.phone).join('\n');

const tgMsg = '✅ 線索清洗完成\n\n' + d.rowsOriginal + ' → ' + d.rowsAfterDedup + ' 筆\n🔥 hot: ' + d.hot + ' / ☀️ warm: ' + d.warm + ' / ❄️ cold: ' + d.cold + '\n\n完整：shared/leads-output/';

return [{
  json: { csvPath: '/files/shared/leads-output/leads-cleaned.csv', mdPath: '/files/shared/leads-output/leads-report.md', tgMsg },
  binary: {
    csv: { data: Buffer.from('\ufeff' + (csv), 'utf-8').toString('base64'), mimeType: 'text/csv', fileName: 'leads-cleaned.csv' },
    md: { data: Buffer.from('\ufeff' + (md), 'utf-8').toString('base64'), mimeType: 'text/markdown', fileName: 'leads-report.md' }
  }
}];
